<template><div class="page"><div><h1>历史户籍归档</h1><p>迁出执行前形成的不可变户籍快照。</p></div><el-card shadow="never"><el-form inline><el-form-item label="姓名"><el-input v-model="query.personName" clearable/></el-form-item><el-form-item label="身份证号"><el-input v-model="query.identityNo" clearable/></el-form-item><el-form-item label="户号"><el-input v-model="query.householdNo" clearable/></el-form-item><el-form-item><el-button type="primary" @click="load">查询</el-button></el-form-item></el-form><el-table :data="rows" v-loading="loading" border><el-table-column prop="personName" label="姓名"/><el-table-column prop="identityNo" label="身份证号" min-width="190"/><el-table-column prop="householdNo" label="户号"/><el-table-column prop="archiveType" label="归档类型" min-width="190"/><el-table-column prop="registeredAddress" label="历史地址" min-width="220"/><el-table-column prop="endDate" label="截止日期"/><el-table-column prop="archivedAt" label="归档时间" min-width="180"/></el-table><AppPagination v-model:current="page" v-model:size="size" :total="total" @change="load"/></el-card></div></template><script setup>import {onMounted,reactive,ref} from 'vue';import {listResidenceArchives} from '../../api/migrations';import AppPagination from '../../components/common/AppPagination.vue';const query=reactive({personName:'',identityNo:'',householdNo:''}),rows=ref([]),loading=ref(false),page=ref(1),size=ref(10),total=ref(0);async function load(){loading.value=true;try{const r=await listResidenceArchives({...query,page:page.value-1,size:size.value});rows.value=r.content||[];total.value=r.totalElements||0}finally{loading.value=false}}onMounted(load);</script><style scoped>.page{display:flex;flex-direction:column;gap:16px}.page h1{margin:0}.page p{color:#64748b}</style>
